SELECT * FROM (
    SELECT A.*, ROW_NUMBER() OVER (ORDER BY A.topYn DESC, A.articleSeq DESC) AS RN
    FROM (
        SELECT 
        FROM FWK_ARTICLE
        WHERE BOARD_ID = #{boardId}
    ) A
) WHERE RN BETWEEN #{offset} + 1 AND #{offset} + #{limit}
ORDER BY RN



SELECT * FROM (
    SELECT A.*, ROW_NUMBER() OVER (ORDER BY A.topYn DESC, ${orderColumn} ${orderDir}, A.articleSeq DESC) AS RN
    FROM (
        SELECT 
        FROM FWK_ARTICLE
        WHERE BOARD_ID = #{boardId}

    ) A
) WHERE RN BETWEEN #{offset} + 1 AND #{offset} + #{limit}
ORDER BY RN

